using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Load raw CSV and map "Yes"/"No" to a boolean Label column
var rawData = mlContext.Data.LoadFromTextFile<CustomerDataRaw>(
    dataPath, hasHeader: true, separatorChar: ',');

var mappingPipeline = mlContext.Transforms.CustomMapping<CustomerDataRaw, LabelMapping>(
    (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
    contractName: "ChurnLabelMapping");

var mappedData = mappingPipeline
    .Append(mlContext.Transforms.CopyColumns("Age", "Age"))
    .Append(mlContext.Transforms.CopyColumns("Income", "Income"))
    .Append(mlContext.Transforms.CopyColumns("Region", "Region"))
    .Append(mlContext.Transforms.CopyColumns("PurchaseHistory", "PurchaseHistory"))
    .Fit(rawData)
    .Transform(rawData);

var split = mlContext.Data.TrainTestSplit(mappedData, testFraction: 0.2, seed: 42);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(split.TrainSet);

// Evaluate — guard against tiny test sets lacking a positive class
var predictions = model.Transform(split.TestSet);
try
{
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                      $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
}
catch (ArgumentOutOfRangeException)
{
    Console.WriteLine("Warning: test set too small for full evaluation — add more data for reliable metrics.");
}

// Save model and register the pooled prediction engine
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer data");

app.MapPost("/predict", (
    PredictionEnginePool<CustomerData, ChurnPrediction> pool,
    CustomerData customer) =>
{
    var result = pool.Predict(customer);
    return Results.Ok(new
    {
        WillChurn = result.Churned,
        Confidence = result.Probability
    });
});

app.Run();

// Helper class for the custom mapping
public class LabelMapping
{
    public bool Label { get; set; }
}

